from dataclasses import dataclass
from datetime import date, timedelta
from enum import Enum
from typing import Optional

class Severity(str, Enum):
    CRITICAL = "critical"
    HIGH = "high"
    MEDIUM = "medium"
    LOW = "low"

FIX_SLA_DAYS: dict[Severity, int] = {
    Severity.CRITICAL: 7,
    Severity.HIGH: 30,
    Severity.MEDIUM: 60,
    Severity.LOW: 90,
}

INTERIM_REQUIRED: dict[Severity, bool] = {
    Severity.CRITICAL: True,
    Severity.HIGH: False,
    Severity.MEDIUM: False,
    Severity.LOW: False,
}

UPDATE_DAYS: dict[Severity, list[int]] = {
    Severity.CRITICAL: [2, 4, 6],
    Severity.HIGH: [14, 28],
    Severity.MEDIUM: [30, 55],
    Severity.LOW: [45, 80],
}

@dataclass
class VDPTimeline:
    submission_id: str
    severity: Severity
    report_date: date
    triage_confirmed_date: Optional[date] = None
    interim_mitigated_date: Optional[date] = None
    fix_deployed_date: Optional[date] = None
    extension_granted_days: int = 0   # max 14

    def disclosure_deadline(self) -> date:
        base = self.report_date + timedelta(days=90)
        return base + timedelta(days=min(self.extension_granted_days, 14))

    def fix_deadline(self) -> Optional[date]:
        if self.triage_confirmed_date is None:
            return None
        return self.triage_confirmed_date + timedelta(days=FIX_SLA_DAYS[self.severity])

    def fix_sla_met(self) -> Optional[bool]:
        if self.fix_deployed_date is None or self.fix_deadline() is None:
            return None
        return self.fix_deployed_date <= self.fix_deadline()

    def interim_overdue(self, today: date) -> bool:
        if not INTERIM_REQUIRED[self.severity]:
            return False
        if self.interim_mitigated_date is not None:
            return False
        if self.triage_confirmed_date is None:
            return False
        return today > self.triage_confirmed_date + timedelta(days=1)

    def next_required_update(self, today: date) -> Optional[date]:
        if self.triage_confirmed_date is None:
            return None
        for day_offset in UPDATE_DAYS[self.severity]:
            update_date = self.triage_confirmed_date + timedelta(days=day_offset)
            if update_date >= today:
                return update_date
        return None

    def days_until_disclosure(self, today: date) -> int:
        return (self.disclosure_deadline() - today).days

    def is_disclosure_overdue(self, today: date) -> bool:
        return today > self.disclosure_deadline() and self.fix_deployed_date is None

    def status_summary(self, today: date) -> str:
        if self.is_disclosure_overdue(today):
            return f"OVERDUE — disclosure deadline passed; researcher may publish"
        if self.interim_overdue(today):
            return f"CRITICAL — interim mitigation overdue"
        days = self.days_until_disclosure(today)
        fix_status = "fixed" if self.fix_deployed_date else "pending"
        return f"Fix: {fix_status} | Disclosure in {days} days | SLA met: {self.fix_sla_met()}"

from dataclasses import dataclass
from datetime import date, timedelta
from typing import Optional

@dataclass
class ExtensionRequest:
    submission_id: str
    requested_by: str         # internal requestor (SPOC)
    requested_at: date
    current_deadline: date
    days_requested: int       # hard cap: 14
    technical_reason: str     # specific, concrete reason
    researcher_contacted: bool
    researcher_consented: Optional[bool] = None
    granted: Optional[bool] = None

    def is_valid(self) -> bool:
        return (
            self.days_requested <= 14 and
            bool(self.technical_reason) and
            self.researcher_contacted
        )

    def new_deadline(self) -> date:
        if not self.granted:
            return self.current_deadline
        return self.current_deadline + timedelta(days=min(self.days_requested, 14))

    def extension_message_to_researcher(self) -> str:
        return (
            f"We are requesting a {self.days_requested}-day extension to the "
            f"disclosure deadline for {self.submission_id}. "
            f"Reason: {self.technical_reason} "
            f"The proposed new deadline would be {self.new_deadline().isoformat()}. "
            f"Please confirm whether you consent to this extension. "
            f"You are not obligated to agree, and the original deadline remains "
            f"in force until you do."
        )
